class MyLinkedList {
public:
    MyLinkedList() : head(nullptr), tail(nullptr), size(0) {

    }

    int get(int index) {
        if (index < 0 || index >= size) return -1;
        Node* current = head;
        for (int i = 0; i < index; ++i) {
            current = current->next;
        }
        return current->val;
    }

    void addAtHead(int val) {
        Node* newNode = new Node(val);
        if (size == 0) {
            head = tail = newNode;
        } else {
            newNode->next = head;
            head = newNode;
        }
        ++size;
    }

    void addAtTail(int val) {
        Node* newNode = new Node(val);
        if (size == 0) {
            head = tail = newNode;
        } else {
            tail->next = newNode;
            tail = newNode;
        }
        ++size;
    }

    void addAtIndex(int index, int val) {
        if (index > size || index < 0) return;
        if (index == 0) {
            addAtHead(val);
        } else if (index == size) {
            addAtTail(val);
        } else {
            Node* prev = head;
            for (int i = 0; i < index - 1; ++i) {
                prev = prev->next;
            }
            Node* newNode = new Node(val);
            newNode->next = prev->next;
            prev->next = newNode;
            ++size;
        }
    }

    void deleteAtIndex(int index) {
        if (index < 0 || index >= size) return;
        if (index == 0) {
            Node* temp = head;
            head = head->next;
            delete temp;
            if (head == nullptr) {
                tail = nullptr;
            }
            --size;
        } else {
            Node* prev = head;
            for (int i = 0; i < index - 1; ++i) {
                prev = prev->next;
            }
            Node* temp = prev->next;
            prev->next = temp->next;
            if (temp == tail) {
                tail = prev;
            }
            delete temp;
            --size;
        }
    }
